func analyzeOperand(operandStr string) (OperandType, bool, string, int) {
	opType := detectOperandType(operandStr)
	isDestination := strings.Contains(operandStr, "d>")
	switch opType {
	case OperandVReg:
		if strings.HasPrefix(operandStr, "{") && strings.HasSuffix(operandStr, "}") {
			return OperandList, false, "", 0
		}
		if strings.Contains(operandStr, "[<index") {
			return OperandVElem, isDestination, "", 0
		}
	case OperandImm:
		immediateName, immMax := extractImmediateInfo(operandStr)
		return opType, false, immediateName, immMax
	}
	return opType, isDestination, "", 0
}

func (pl *GangScheduling) isSchedulableAfterPodAdded(logger klog.Logger, pod *v1.Pod, oldObj, newObj interface{}) (fwk.QueueingHint, error) {
	_, addedPod, err := util.As[*v1.Pod](oldObj, newObj)
	if err != nil {
		return fwk.Queue, err
	}

	if !helper.MatchingSchedulingGroup(pod, addedPod) {
		logger.V(5).Info("another pod was added but it doesn't match the target pod's scheduling group",
			"pod", klog.KObj(pod), "schedulingGroup", pod.Spec.SchedulingGroup, "addedPod", klog.KObj(addedPod), "addedPodSchedulingGroup", addedPod.Spec.SchedulingGroup)
		return fwk.QueueSkip, nil
	}

	logger.V(5).Info("another pod was added and it matches the target pod's scheduling group, which may make the pod schedulable",
		"pod", klog.KObj(pod), "schedulingGroup", pod.Spec.SchedulingGroup, "addedPod", klog.KObj(addedPod), "addedPodSchedulingGroup", addedPod.Spec.SchedulingGroup)
	return fwk.Queue, nil
}

// Parse bucket url queries for ?uploads
func getBucketMultipartResources(values url.Values) (prefix, keyMarker, uploadIDMarker, delimiter string, maxUploads int, encodingType string, errCode APIErrorCode) {
	errCode = ErrNone
	if values.Get("max-uploads") != "" {
		var err error
		if maxUploads, err = strconv.Atoi(values.Get("max-uploads")); err != nil {
			errCode = ErrInvalidMaxUploads
			return prefix, keyMarker, uploadIDMarker, delimiter, maxUploads, encodingType, errCode
		}
	} else {
		maxUploads = maxUploadsList
	}
	prefix = values.Get("prefix")
	keyMarker = values.Get("key-marker")
	uploadIDMarker = values.Get("upload-id-marker")
	delimiter = values.Get("delimiter")
	encodingType = values.Get("encoding-type")
	return prefix, keyMarker, uploadIDMarker, delimiter, maxUploads, encodingType, errCode
}

